import{_ as t,o as s,c as i,a2 as a}from"./chunks/framework.jWxB9oXr.js";const k=JSON.parse('{"title":"Layout Coordinate Systems","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Layout Coordinate Systems"}],["meta",{"property":"og:description","content":"Layout Coordinate Systems — an in-depth guide for building terminal apps with Silvery."}],["meta",{"property":"og:url","content":"https://silvery.dev/guide/layout-coordinates.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/guide/layout-coordinates.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Guide\\",\\"item\\":\\"https://silvery.dev/guide\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Layout Coordinate Systems\\",\\"item\\":\\"https://silvery.dev/guide/layout-coordinates\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Layout Coordinate Systems\\",\\"description\\":\\"Layout Coordinate Systems — an in-depth guide for building terminal apps with Silvery.\\",\\"url\\":\\"https://silvery.dev/guide/layout-coordinates.html\\",\\"dateModified\\":\\"2026-04-09T21:03:51.000Z\\",\\"datePublished\\":\\"2026-04-09T21:03:51.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"guide/layout-coordinates.md","filePath":"guide/layout-coordinates.md","lastUpdated":1775768631000}'),n={name:"guide/layout-coordinates.md"};function o(d,e,r,l,h,c){return s(),i("div",null,[...e[0]||(e[0]=[a(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide/layout-coordinates.md for this page in Markdown format</div><h1 id="layout-coordinate-systems" tabindex="-1">Layout Coordinate Systems <a class="header-anchor" href="#layout-coordinate-systems" aria-label="Permalink to &quot;Layout Coordinate Systems&quot;">​</a></h1><p>Every silvery node has three rects. They differ only in how scroll and sticky offsets are applied. Picking the right one is the difference between a hover that lands on the right pixel and one that lands on the wrong row when a sticky header is visible.</p><h2 id="the-three-rects" tabindex="-1">The three rects <a class="header-anchor" href="#the-three-rects" aria-label="Permalink to &quot;The three rects&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rect</th><th>Hook</th><th>What it represents</th><th>CSS analogue</th></tr></thead><tbody><tr><td><code>boxRect</code></td><td><code>useBoxRect()</code></td><td>Layout position within the node&#39;s flow. Border-box sized.</td><td><code>offsetLeft/Top</code> + size</td></tr><tr><td><code>scrollRect</code></td><td><code>useScrollRect()</code></td><td>Scroll-adjusted position <strong>before</strong> sticky clamping. Can go off-screen.</td><td><em>(no direct CSS equivalent)</em></td></tr><tr><td><code>screenRect</code></td><td><code>useScreenRect()</code></td><td>Actual paint position on the terminal screen.</td><td><code>getBoundingClientRect()</code></td></tr></tbody></table><p>All three are <code>{ x, y, width, height }</code>. The width and height are identical across all three (they&#39;re the same box, just in different coordinate systems). Only <code>x</code> and <code>y</code> change between them.</p><h2 id="when-to-use-each" tabindex="-1">When to use each <a class="header-anchor" href="#when-to-use-each" aria-label="Permalink to &quot;When to use each&quot;">​</a></h2><p>Use <code>useBoxRect()</code> when you need the node&#39;s <strong>own layout dimensions</strong> — width/height for responsive rendering, position within the parent for relative math. This is the most common hook.</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Header</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  const</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> useBoxRect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">repeat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(width)}&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Use <code>useScrollRect()</code> when you need the node&#39;s <strong>scroll-adjusted logical position</strong> — where it &quot;would be&quot; in the scrolled document. Useful for scroll calculations and virtual lists that need to reason about the full document flow.</p><p>Use <code>useScreenRect()</code> when you need the <strong>actual paint position</strong> on the terminal. This is the right choice for:</p><ul><li>Hit testing (which node did the mouse click?)</li><li>Cursor positioning (where does IME composition go?)</li><li>Cross-component visual navigation (arrow-key traversal across columns)</li><li>Anything that cares about where pixels actually land</li></ul><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">onLayout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Register the card&#39;s screen position so arrow-key navigation</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // can find &quot;the card visually closest to row N&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  useScreenRect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">rect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> onLayout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(id, rect.y))</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Box</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;...&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Box</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="reactive-vs-callback" tabindex="-1">Reactive vs callback <a class="header-anchor" href="#reactive-vs-callback" aria-label="Permalink to &quot;Reactive vs callback&quot;">​</a></h2><p>Each hook has two call signatures:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Reactive — re-renders when the rect changes</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> rect</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> useBoxRect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Callback — zero re-renders, the callback fires after layout</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useBoxRect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">rect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> register</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(id, rect))</span></span></code></pre></div><p>Use the reactive form for components that need to <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> differently based on their size. Use the callback form for hot paths — large lists, position registries, and anywhere re-rendering on every layout change would be prohibitive.</p><h2 id="why-the-distinction-exists-—-sticky-nodes" tabindex="-1">Why the distinction exists — sticky nodes <a class="header-anchor" href="#why-the-distinction-exists-—-sticky-nodes" aria-label="Permalink to &quot;Why the distinction exists — sticky nodes&quot;">​</a></h2><p>For most nodes, <code>scrollRect</code> and <code>screenRect</code> are identical. The distinction only matters for <code>position=&quot;sticky&quot;</code> nodes.</p><p>Imagine a scrollable column with a sticky header. After scrolling down 5 rows, the sticky header&#39;s logical flow position moves off-screen — but the sticky behavior pins it to the top of the <span class="glossary-hint" data-tooltip="The visible portion of the terminal — rows × cols currently displayed to the user">viewport</span>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Before scroll:                  After scroll 5 rows:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─ Column ───────┐              ┌─ Column ───────┐</span></span>
<span class="line"><span>│ Sticky Header  │  ← row 0     │ Sticky Header  │  ← pinned at row 0</span></span>
<span class="line"><span>│ Card A         │  ← row 1     │ Card F         │  ← row 1</span></span>
<span class="line"><span>│ Card B         │  ← row 2     │ Card G         │  ← row 2</span></span>
<span class="line"><span>│ ...            │              │ ...            │</span></span>
<span class="line"><span>└────────────────┘              └────────────────┘</span></span></code></pre></div><p>For the sticky header after scrolling:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">scrollRect.y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // flow position, would be off-screen</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">screenRect.y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // actual paint position, clamped to top</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">boxRect.y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // position within parent container (unchanged)</span></span></code></pre></div><p>That&#39;s the whole reason for having two hooks. <code>scrollRect</code> gives you the &quot;true&quot; document position (so you can check <em>is this node scrolled past?</em>), <code>screenRect</code> gives you the paint position (so your hit test doesn&#39;t click through a sticky header).</p><h2 id="comparison-with-other-frameworks" tabindex="-1">Comparison with other frameworks <a class="header-anchor" href="#comparison-with-other-frameworks" aria-label="Permalink to &quot;Comparison with other frameworks&quot;">​</a></h2><p>Silvery is the only React TUI framework that distinguishes all three coordinate systems:</p><table tabindex="0"><thead><tr><th>Framework</th><th>Size</th><th>Layout position</th><th>Scroll-adjusted</th><th>Paint position</th></tr></thead><tbody><tr><td><strong>Silvery</strong></td><td><code>useBoxRect()</code> (width/height)</td><td><code>useBoxRect()</code> (x/y)</td><td><code>useScrollRect()</code></td><td><code>useScreenRect()</code></td></tr><tr><td><a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> (7.0)</td><td><code>useBoxMetrics(ref)</code></td><td><code>useBoxMetrics(ref)</code></td><td><em>(no scroll)</em></td><td><em>(no scroll)</em></td></tr><tr><td>Textual (Python)</td><td><code>Size</code></td><td><code>Widget.region</code></td><td><code>Widget.virtual_region</code></td><td><code>Widget.window_region</code></td></tr><tr><td>blessed</td><td><code>.width</code>/<code>.height</code></td><td><code>.left</code>/<code>.top</code> + <code>.atop</code> etc.</td><td><code>.childBase</code> + <code>.childOff</code></td><td><code>.aleft</code>/<code>.atop</code></td></tr><tr><td>Ratatui (Rust)</td><td><code>Rect</code></td><td><code>Rect</code></td><td>per-widget <code>offset</code></td><td>—</td></tr><tr><td>Bubble Tea</td><td><code>WindowSizeMsg</code></td><td><em>(manual)</em></td><td><code>viewport.YOffset</code></td><td><em>(manual)</em></td></tr></tbody></table><p><a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> has no scroll concept, so its single <code>useBoxMetrics</code> hook is equivalent to silvery&#39;s <code>useBoxRect</code> in unscrolled contexts. Textual has the closest vocabulary to silvery&#39;s, with distinct types for each coordinate system.</p><h2 id="design-notes" tabindex="-1">Design notes <a class="header-anchor" href="#design-notes" aria-label="Permalink to &quot;Design notes&quot;">​</a></h2><h3 id="why-boxrect-instead-of-contentrect" tabindex="-1">Why <code>boxRect</code> instead of <code>contentRect</code> <a class="header-anchor" href="#why-boxrect-instead-of-contentrect" aria-label="Permalink to &quot;Why \`boxRect\` instead of \`contentRect\`&quot;">​</a></h3><p>The property is border-box sized — it includes padding and border, matching <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>&#39;s <code>getComputedWidth/Height</code>. The CSS &quot;content-box&quot; is inside padding and border, so &quot;contentRect&quot; was a CSS-misleading name. Matching <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0&#39;s <code>useBoxMetrics</code> terminology avoids the box-model ambiguity.</p><h3 id="why-screenrect-is-the-paint-position" tabindex="-1">Why <code>screenRect</code> is the paint position <a class="header-anchor" href="#why-screenrect-is-the-paint-position" aria-label="Permalink to &quot;Why \`screenRect\` is the paint position&quot;">​</a></h3><p>&quot;<a href="/components/Screen" class="hover-link" data-tooltip="Root layout component — fills the terminal viewport with flexbox column layout">Screen</a>&quot; in terminal-land means the visible <span class="glossary-hint" data-tooltip="The visible portion of the terminal — rows × cols currently displayed to the user">viewport</span> — the terminal window. It maps cleanly to CSS <code>getBoundingClientRect()</code> for anyone coming from the web, and it&#39;s the name most terminal developers reach for first. The CSS &quot;screen&quot; (physical monitor) is not a concept that exists in terminal rendering.</p><p>When silvery grows beyond the terminal (canvas, DOM), <code>screenRect</code> may be reconsidered — canvas has no fixed &quot;screen&quot; coordinate system. But for terminal-first work, it&#39;s the clearest name.</p>`,34)])])}const y=t(n,[["render",o]]);export{k as __pageData,y as default};
